mapper.update:
UPDATE HOMPI_GUEST_BOOK
SET
GUEST_BOOK_CONTENT = #{guestBookContent},
UPDATE_DT = #{updateDt},
UPDATE_USER_ID = #{updateUserId}
WHERE GUEST_BOOK_ID = #{guestBookId}

mapper.delete:
DELETE FROM HOMPI_GUEST_BOOK
WHERE GUEST_BOOK_ID = #{guestBookId}
AND INSERT_USER_ID = #{userId}

mapper.select:
SELECT COUNT(*)
FROM HOMPI_GUEST_BOOK
WHERE HOMPI_ID = #{hompiId}
